  }

  // ── effect burst zone + animated pixel sparks at the target ──
  if (uni(28) > 0.01) {
    let tgt = vec2f(uni(31), uni(32));
    if (hex_dist(px_hex(tgt), gh) <= 1 && (gland == 0 || gland == 1)) {
      col += vec3f(uni(33), uni(34), uni(35)) * 0.22 * uni(28);
    }
    let bs = iso_scr(tgt, 10.0);
    for (var si = 0; si < 12; si++) {
      let hsh = hash22(vec2f(f32(si) * 3.7, uni(39)));
      let sa = hsh.x * 6.2831853;
      let sp2 = bs + vec2f(cos(sa), sin(sa) * 0.6) * (1.0 - uni(28)) * (16.0 + hsh.y * 26.0);
      if (length(floor(p / 2.0) * 2.0 - floor(sp2 / 2.0) * 2.0) < 1.4) {
        col += vec3f(uni(33), uni(34), uni(35)) * uni(28) * 2.5;
      }
    }
  }

  // ── the effect ray + burst (visual controllers) ──
  if (uni(28) > 0.01) {
    let a = iso_scr(vec2f(uni(29), uni(30)), 12.0);
    let b = iso_scr(vec2f(uni(31), uni(32)), 12.0);
    let ab = b - a;
    let tt = clamp(dot(p - a, ab) / max(dot(ab, ab), 0.001), 0.0, 1.0);
    let dl = length(p - (a + ab * tt));
    let rc = vec3f(uni(33), uni(34), uni(35));
    col += rc * uni(28) * exp(-dl * 0.55);
    col += rc * uni(28) * 1.6 * exp(-length(p - b) * 0.10);        // burst at the target
  }

  // ── quest props on the ground ──
  if (room == 2 && uni(10) < 0.5) {
    let kp = p - iso_scr(vec2f(385.00, 143.94), 8.0);
    let kd = sdBox(rotate(kp, 0.785), vec2f(5.0, 5.0));
    col += vec3f(2.2, 1.6, 0.4) * (0.7 + 0.3 * sin(t * 4.0)) * exp(-max(kd, 0.0) * 0.22);
  }
  if (room == 3) {
    let cp = p - iso_scr(vec2f(250.00, 117.96), 8.0);
    let cd = sdBox(cp, vec2f(12.0, 8.0));
    if (cd < 0.0) {
      col = mix(vec3f(0.26, 0.15, 0.06), vec3f(0.42, 0.26, 0.10), step(cp.y, -2.0));
      if (uni(11) > 0.5) { col += vec3f(1.8, 1.3, 0.4); }
    }
    col += vec3f(3.0, 2.3, 1.0) * uni(8) * exp(-length(cp) * 0.012);
  }
  if (room == 1) {
    let dp = length(p - iso_scr(vec2f(430.00, 221.88), 0.0));
    var dc = vec3f(0.2, 0.9, 1.0);

    col += dc * 0.45 * (0.5 + 0.3 * sin(t * 2.0)) * exp(-max(dp - ES * 0.35, 0.0) * 0.16);
  }
  if (room == 1) {
    let dp = length(p - iso_scr(vec2f(205.00, 143.94), 0.0));
    var dc = vec3f(0.2, 0.9, 1.0);
    if (uni(10) < 0.5) { dc = vec3f(1.0, 0.15, 0.1); }
    col += dc * 0.45 * (0.5 + 0.3 * sin(t * 2.0)) * exp(-max(dp - ES * 0.35, 0.0) * 0.16);
  }
  if (room == 2) {
    let dp = length(p - iso_scr(vec2f(70.00, 221.88), 0.0));
    var dc = vec3f(0.2, 0.9, 1.0);

    col += dc * 0.45 * (0.5 + 0.3 * sin(t * 2.0)) * exp(-max(dp - ES * 0.35, 0.0) * 0.16);
  }
  if (room == 3) {
    let dp = length(p - iso_scr(vec2f(250.00, 377.77), 0.0));
    var dc = vec3f(0.2, 0.9, 1.0);

    col += dc * 0.45 * (0.5 + 0.3 * sin(t * 2.0)) * exp(-max(dp - ES * 0.35, 0.0) * 0.16);
  }

  // ── iso extrusion: stone prisms and forest canopies rise off the board ──
  // sides first (sampled down the column), then tops — later writes win
  for (var hs = 0; hs < 4; hs++) {
    let hh = f32(hs) * 5.50 + 3.0;
    let gs = iso_plan(p, hh);
    let sh = px_hex(gs);
    if (esp_land(room, sh.x, sh.y) == 2) {
      let rk = fbm3(gs * 0.09 + f32(sh.x + sh.y));
      col = mix(vec3f(0.055, 0.055, 0.065), vec3f(0.115, 0.11, 0.105), rk) * (0.55 + 0.45 * hh / 22.00);
    }
  }
  {
    let gt = iso_plan(p, 22.00);
    let th = px_hex(gt);
    if (esp_land(room, th.x, th.y) == 2) {
      let tc = hex_px(th);
      let trad = length(gt - tc);
      let rk = fbm3(gt * 0.08);
      col = mix(vec3f(0.10, 0.10, 0.115), vec3f(0.185, 0.175, 0.165), rk);
      col *= 0.78 + 0.45 * smoothstep(ES, 0.0, trad);               // domed top, lit
      col += vec3f(0.03, 0.035, 0.045) * smoothstep(3.0, 0.0, abs(trad - ES * 0.80));
    }
  }
  {
    // trunks
    let gk = iso_plan(p, 6.0);
    let kh = px_hex(gk);
    if (esp_land(room, kh.x, kh.y) == 1 && length(gk - hex_px(kh)) < 3.5) {
      col = vec3f(0.09, 0.06, 0.035);
    }
    // canopies
    let gf = iso_plan(p, 32.00);
    let fh = px_hex(gf);
    if (esp_land(room, fh.x, fh.y) == 1) {
      let fc2 = hex_px(fh);
      let frad = length(gf - fc2);
      if (frad < ES * 0.92) {
        let leaf = fbm3(gf * 0.11 + vec2f(f32(fh.x) * 3.1, f32(fh.y) * 5.7) + vec2f(sin(t * 0.7 + f32(fh.y)) * 0.8, 0.0));
        var fc = mix(vec3f(0.020, 0.060, 0.028), vec3f(0.080, 0.155, 0.062), leaf);
        if (room == 2) { fc = mix(vec3f(0.032, 0.048, 0.068), vec3f(0.080, 0.105, 0.135), leaf); }
        fc *= 0.60 + 0.55 * smoothstep(ES * 0.9, ES * 0.1, length(gf - fc2 + vec2f(6.0, 6.0)));  // NW crown light
        col = fc;
      }
    }
  }

  // ── characters: billboards standing on the board ──
  {
    let st = uni(15);
    if (st > -0.5 && st < 2.5) {
      let ep = p - iso_scr(vec2f(uni(12), uni(13)), 9.0);
      let ed = length(ep) - 7.5;
      if (ed < 2.0) {
        var bc = vec3f(0.30, 0.34, 0.38);
        if (st > 0.5) { bc = vec3f(0.55, 0.28, 0.78); }
        if (st > 1.5) { bc = vec3f(1.7, 0.14, 0.18); }
        if (ed < 0.0) {
          col = mix(bc, bc * 0.42, smoothstep(-7.5, 0.0, ed));
          let fd = vec2f(cos(uni(14)), sin(uni(14)) * ISY);
          if (length(ep - normalize(fd) * 4.8) < 2.4) { col = vec3f(1.0, 0.95, 0.85); }
        } else if (st > 0.5) { col = mix(col, bc, 0.7 * (0.5 + 0.5 * sin(t * 8.0))); }
      }
      // ground contact shadow
      let sp = length(p - iso_scr(vec2f(uni(12), uni(13)), 0.0));
      col *= 1.0 - 0.35 * smoothstep(7.0, 2.0, sp);
    }
  }
  {
    let st = uni(19);
    if (st > -0.5 && st < 2.5) {
      let ep = p - iso_scr(vec2f(uni(16), uni(17)), 9.0);
      let ed = length(ep) - 7.5;
      if (ed < 2.0) {
        var bc = vec3f(0.30, 0.34, 0.38);
        if (st > 0.5) { bc = vec3f(0.55, 0.28, 0.78); }
        if (st > 1.5) { bc = vec3f(1.7, 0.14, 0.18); }
        if (ed < 0.0) {
          col = mix(bc, bc * 0.42, smoothstep(-7.5, 0.0, ed));
          let fd = vec2f(cos(uni(18)), sin(uni(18)) * ISY);
          if (length(ep - normalize(fd) * 4.8) < 2.4) { col = vec3f(1.0, 0.95, 0.85); }
        } else if (st > 0.5) { col = mix(col, bc, 0.7 * (0.5 + 0.5 * sin(t * 8.0))); }
      }
      // ground contact shadow
      let sp = length(p - iso_scr(vec2f(uni(16), uni(17)), 0.0));
      col *= 1.0 - 0.35 * smoothstep(7.0, 2.0, sp);
    }
  }
  {
    let st = uni(23);
    if (st > -0.5 && st < 2.5) {
      let ep = p - iso_scr(vec2f(uni(20), uni(21)), 9.0);
      let ed = length(ep) - 7.5;
      if (ed < 2.0) {
        var bc = vec3f(0.30, 0.34, 0.38);
        if (st > 0.5) { bc = vec3f(0.55, 0.28, 0.78); }
        if (st > 1.5) { bc = vec3f(1.7, 0.14, 0.18); }
        if (ed < 0.0) {
          col = mix(bc, bc * 0.42, smoothstep(-7.5, 0.0, ed));
          let fd = vec2f(cos(uni(22)), sin(uni(22)) * ISY);
          if (length(ep - normalize(fd) * 4.8) < 2.4) { col = vec3f(1.0, 0.95, 0.85); }
        } else if (st > 0.5) { col = mix(col, bc, 0.7 * (0.5 + 0.5 * sin(t * 8.0))); }
      }
      // ground contact shadow
      let sp = length(p - iso_scr(vec2f(uni(20), uni(21)), 0.0));
      col *= 1.0 - 0.35 * smoothstep(7.0, 2.0, sp);
    }
  }
  {
    let hp = p - iso_scr(vec2f(uni(1), uni(2)), 9.0);
    let hd = length(hp) - 7.5;
    let sp = length(p - iso_scr(vec2f(uni(1), uni(2)), 0.0));
    col *= 1.0 - 0.35 * smoothstep(7.0, 2.0, sp);
    if (hd < 0.0) {
      var hc = mix(vec3f(0.07, 0.26, 0.28), vec3f(0.21, 0.58, 0.60), smoothstep(-7.5, -1.6, hd));
      if (hd > -1.6) { hc *= 0.4; }
      if (uni(5) > 0.0) { hc += vec3f(0.15, 0.25, 0.7) * (0.5 + 0.5 * sin(t * 12.0)); }
      let dir = vec2f(cos(uni(3)), sin(uni(3)) * ISY);
      if (length(hp - normalize(dir) * 4.8) < 2.3) { hc = vec3f(0.95, 0.9, 0.75); }
      col = mix(hc, col, max(uni(4) * 0.55, min(uni(5), 1.0) * 0.6));
    }
  }

  // vignettes: alert pulse, capture flash
  var anyAlert = uni(7) > 2.5;
  if (uni(15) > 1.5 && uni(15) < 2.5) { anyAlert = true; }
  if (uni(19) > 1.5 && uni(19) < 2.5) { anyAlert = true; }
  if (uni(23) > 1.5 && uni(23) < 2.5) { anyAlert = true; }
  if (anyAlert) { col += vec3f(0.5, 0.02, 0.03) * (0.5 + 0.5 * sin(t * 6.0)) * smoothstep(0.55, 1.0, length(uv)); }
  col += vec3f(1.2, 0.0, 0.0) * uni(24) * smoothstep(0.45, 1.0, length(uv));

  // ── the hand: card UI in SCREEN space (immune to the camera) ──
  let ps = (uv + vec2f(1.0)) * 256.0;
  for (var ci = 0; ci < 4; ci++) {
    var cc = vec3f(2.4, 0.5, 0.3);                                 // fire
    if (ci == 1) { cc = vec3f(0.5, 1.1, 2.2); }                    // psychic
    if (ci == 2) { cc = vec3f(0.55, 0.35, 0.95); }                 // shadow
    if (ci == 3) { cc = vec3f(0.45, 0.42, 0.50); }                 // silent kill: black card, grey edge
    let armed = i32(uni(42) + 0.5) == ci;
    var cy = 474.0;
    if (armed) { cy = 466.0; }
    let cp = ps - vec2f(256.0 + (f32(ci) - 1.5) * 64.0, cy);
    let cd = sdRoundedBox(cp, vec2f(26.0, 17.0), 4.0);
    if (cd < 0.0) {
      col = vec3f(0.050, 0.058, 0.078);
      if (ci == 3) { col = vec3f(0.012, 0.012, 0.018); }           // black as the deed
      if (cd > -2.0) { col = cc * select(0.35, 0.8, armed); }      // border
      // sigils
      if (ci == 0 && sdBox(rotate(cp + vec2f(0.0, 3.0), 0.785), vec2f(4.5, 4.5)) < 0.0) { col = cc * 0.9; }
      if (ci == 1 && abs(length(cp + vec2f(0.0, 3.0)) - 5.0) < 1.5) { col = cc * 0.9; }
      if (ci == 2 && length(cp + vec2f(1.0, 3.0)) < 5.5 && length(cp + vec2f(-2.0, 4.0)) > 4.5) { col = cc * 0.9; }
      if (ci == 3) {
        if (sdBox(cp + vec2f(0.0, 2.0), vec2f(1.1, 6.0)) < 0.0) { col = cc * 1.1; }   // blade
        if (sdBox(cp + vec2f(0.0, 6.0), vec2f(4.0, 1.1)) < 0.0) { col = cc * 1.1; }   // guard
      }
      // charge pips
      if (ci == 3) {
        // infinite uses: the lemniscate
        if (abs(length(cp - vec2f(-3.5, -10.0)) - 2.6) < 1.1) { col = cc * 1.2; }
        if (abs(length(cp - vec2f(3.5, -10.0)) - 2.6) < 1.1) { col = cc * 1.2; }
      } else {
        var pips = uni(40);
        if (ci == 1) { pips = uni(41); }
        if (ci == 2) { pips = uni(6); }
        for (var pi = 0; pi < 3; pi++) {
          if (f32(pi) < pips && length(cp - vec2f((f32(pi) - 1.0) * 9.0, -10.0)) < 2.4) { col = cc * 1.2; }
        }
      }
    }
    if (armed) { col += cc * 0.20 * exp(-max(cd, 0.0) * 0.18); }   // armed glow
  }

  return vec4f(col, 1.0);
}

fn cf_portal_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.073, 0.021); }
  if (i == 1) { return vec2f(-0.179, -0.008); }
  if (i == 2) { return vec2f(0.16, -0.15); }
  if (i == 3) { return vec2f(0.001, 0.19); }
  if (i == 4) { return vec2f(-0.219, -0.196); }
  if (i == 5) { return vec2f(0.357, 0.002); }
  if (i == 6) { return vec2f(-0.309, 0.157); }
  if (i == 7) { return vec2f(0.071, -0.326); }
  if (i == 8) { return vec2f(0.242, 0.259); }
  if (i == 9) { return vec2f(-0.458, -0.11); }
  if (i == 10) { return vec2f(0.442, -0.191); }
  if (i == 11) { return vec2f(-0.177, 0.344); }
  return vec2f(0.0, 0.0);
}
fn cf_style(i: i32) -> i32 {
  if (i == 0) { return 8; }
  if (i == 1) { return 2; }
  if (i == 2) { return 8; }
  if (i == 3) { return 8; }
  if (i == 4) { return 8; }
  if (i == 5) { return 6; }
  if (i == 6) { return 7; }
  if (i == 7) { return 8; }
  if (i == 8) { return 8; }
  if (i == 9) { return 8; }
  if (i == 10) { return 1; }
  if (i == 11) { return 0; }
  return 8;
}
fn cf_hue(i: i32) -> f32 {
  if (i == 0) { return 0.420; }
  if (i == 1) { return 0.980; }
  if (i == 2) { return 0.660; }
  if (i == 3) { return 0.990; }
  if (i == 4) { return 0.160; }
  if (i == 5) { return 0.130; }
  if (i == 6) { return 0.400; }
  if (i == 7) { return 0.760; }
  if (i == 8) { return 0.960; }
  if (i == 9) { return 0.250; }
  if (i == 10) { return 0.050; }
  if (i == 11) { return 0.720; }
  return 0.5;
}

fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(0), uni(1));     // cursor in field coords

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── every cartridge on the shelf, newest nearest the center ──
  for (var i = 0; i < 12; i++) {
    let ctr = cf_portal_pos(i);
    let d = length(uv - ctr);
    let R = 0.088;
    let hov = uni(2 + i);                          // 0..1 hover bloom from the hook
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      let st = cf_style(i);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let hue = cf_hue(i);
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}
